  platform_parameters: isObject(writer.platform_parameters) ? writer.platform_parameters : {},
  used_knowledge_blocks: asArray(writer.used_knowledge),
  quality_score: null
};

return [
  {
    json: {
      ...parsed,
      prompt_request_id,
      workspace_id,
      user_id,
      project_id,
      output_type,
      platform,
      writer_result: writer,
      generated_output_payload,
      can_create_generated_output: errors.length === 0,
      errors: [...new Set(errors)]
    }
  }
];

function safeFirst(name) {
  try {
    return $(name).first().json || {};
  } catch (e) {
    return {};
  }
}

function collectErrors(...sources) {
  const out = [];
  for (const source of sources) {
    if (Array.isArray(source)) {
      out.push(...source.filter(Boolean));
    }
  }
  return [...new Set(out)];
}

const validated = safeFirst('Validate WF-01 Handoff');
const loaded = safeFirst('Validate Loaded Prompt Request');
const parsed = safeFirst('Parse and Validate Prompt Writer JSON');
const prepared = safeFirst('Prepare Generated Output Payload');
const created = safeFirst('Create Generated Output');
const updated = safeFirst('Update Prompt Request To Validating');

const base =
  Object.keys(prepared).length ? prepared :
  Object.keys(parsed).length ? parsed :
  Object.keys(loaded).length ? loaded :
  validated;

let errors = collectErrors(
  validated.errors,
  loaded.errors,
  parsed.errors,
  prepared.errors
);

if (created && created.error) {
  errors.push(`generated_output_create_failed:${created.error.message || created.error}`);
}

const generated_output_id =
  created && created.id && !created.error
    ? created.id
    : null;

if (!generated_output_id) {
  errors.push('generated_output_id_missing_after_create');
}

if (generated_output_id && updated && updated.error) {
  errors.push(`prompt_request_status_update_failed:${updated.error.message || updated.error}`);
}

errors = [...new Set(errors)];

const success = Boolean(generated_output_id) && errors.length === 0;

return [
  {
    json: {
      wf10_status: success ? 'generated' : 'failed',
      prompt_request_id: base.prompt_request_id || validated.prompt_request_id || null,
      generated_output_id,
      workspace_id: base.workspace_id || validated.workspace_id || null,
      user_id: base.user_id || validated.user_id || null,
      project_id: base.project_id || validated.project_id || null,
      output_type: base.output_type || validated.output_type || null,
      platform: base.platform || validated.platform || null,
      generation_layer: success ? 'layer_1_draft' : null,
      next_workflow: success ? 'WF-11 Prompt Validation And Improvement Engine' : null,
      handoff_payload: success ? {
        prompt_request_id: base.prompt_request_id || validated.prompt_request_id || null,
        generated_output_id,
        workspace_id: base.workspace_id || validated.workspace_id || null,
        user_id: base.user_id || validated.user_id || null,
        project_id: base.project_id || validated.project_id || null,
        output_type: base.output_type || validated.output_type || null,
        platform: base.platform || validated.platform || null,
        generation_layer: 'layer_1_draft'
      } : null,
      errors: success ? [] : errors,
      debug: {
        prepared_prompt_request_id: prepared.prompt_request_id || null,
        generated_output_payload_prompt_request_id: prepared.generated_output_payload?.prompt_request_id || null,
        create_generated_output_raw: created || null
      }
    }
  }
];

const allowedKeys = [
  'wf10_status',
  'prompt_request_id',
  'generated_output_id',
  'workspace_id',
  'user_id',
  'project_id',
  'output_type',
  'platform',
  'generation_layer',
  'next_workflow',
  'handoff_payload',
  'errors',
  'debug'
];

const out = {};

for (const key of allowedKeys) {
  out[key] = $json[key] ?? null;
}

if (!Array.isArray(out.errors)) {
  out.errors = [];
}

return [
  {
    json: out
  }
];
